app.post('/api/query/:collection/distinct', async (req, res) => {
  try {
    const { collection } = req.params;
    const { field, filter = {} } = req.body;

    if (!field) {
      return res.status(400).json({
        success: false,
        error: 'Field parameter is required'
      });
    }

    const sanitizedFilter = sanitizeQuery(filter);
    const values = await db.collection(collection).distinct(field, sanitizedFilter);

    res.json({
      success: true,
      field,
      values,
      count: values.length
    });
  } catch (error) {
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
});

